mapper.select:

SELECT * FROM (
    SELECT a.*, rownum rnum FROM (
        SELECT * FROM INQUIRY 
        ORDER BY inquiry_id DESC
    ) a
) WHERE rnum >= #{startRow} AND rnum <= #{endRow}

mapper.update:
UPDATE INQUIRY 
SET admin_reply = #{admin_reply}, 
    status = 'ANSWERED',  answered_at = SYSTIMESTAMP WHERE inquiry_id = #{inquiry_id}

mapper.insert:
INSERT INTO FAQ (
    faq_id, admin_id, question, answer, category, order_no, visible, created_at
) VALUES (
    faq_seq.nextval, #{admin_id}, #{question}, #{answer}, #{category}, #{order_no}, #{visible}, SYSTIMESTAMP
)
